# Whitelist of safe built-ins and constants
_WHITELIST = {
    'abs', 'all', 'any', 'bool', 'complex', 'dict', 'float', 'int', 'len', 'list', 'max', 'min', 
    'pow', 'round', 'set', 'str', 'sum', 'tuple', 'zip', 'filter', 'sorted', 'isinstance', 
