    'format', 'slice', 'bytearray', 'bytes', 'object', 'type',
    'True', 'False', 'None'
}

# Build safe globals dictionary
_SAFE_GLOBALS = {}
for name in _WHITELIST:
    if name == 'True':
        _SAFE_GLOBALS[name] = True
    elif name == 'False':
        _SAFE_GLOBALS[name] = False
    elif name == 'None':
        _SAFE_GLOBALS[name] = None
    else:
        if hasattr(builtins, name):
            _SAFE_GLOBALS[name] = getattr(builtins, name)

def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided Python expression string.

    Args:
        transform_map_expr: A Python dictionary literal expression string 
                            that defines the transformation. The expression 
                            can reference the input data via 'input_data'.
        input_data: The dictionary containing data from the previous workflow step.

    Returns:
        The transformed dictionary after evaluating the expression.

    Raises:
        ValueError: If there's an error evaluating the expression.
        TypeError: If the evaluated result is not a dictionary.
    """
    local_vars = {'input_data': input_data}
    try:
        result = eval(transform_map_expr, _SAFE_GLOBALS, local_vars)
    except Exception as e:
        raise ValueError(f"Error evaluating expression: {transform_map_expr}") from e

    if not isinstance(result, dict):
        raise TypeError(f"Expression must return a dictionary, got {type(result).__name__}")

    return result
